data.content:
Contents of file console/templates/confirm.html:

1 | {% extends "base.html" %}
2 | {% block title %}Decision recorded &middot; Catalyst Integrity Desk{% endblock %}
3 | {% block content %}
4 | 
5 | <h1>Decision recorded</h1>
6 | 
7 | {# ------------------------------------------------------------------
8 |    Decision receipt: who decided, what changed, the timestamp,
9 |    the previous ledger hash, the new ledger hash, thesis state.
10 |    Hashes come from ledger entries -- the chain is the proof.
11 |    ------------------------------------------------------------------ #}
12 | <div style="background:#161b22; border:1px solid #30363d; border-radius:6px;
13 |             padding:20px; max-width:720px; margin-bottom:24px;">
14 | 
15 |   {# Verdict + integrity badge side by side #}
16 |   <div style="display:flex; align-items:center; justify-content:space-between;
17 |               margin-bottom:20px;">
18 |     <div>
19 |       <span style="font-size:11px; color:#8b949e; text-transform:uppercase;
20 |                    letter-spacing:0.07em;">Verdict</span>
21 |       <div style="margin-top:4px;">
22 |         {% if verdict == "approve" %}
23 |           <span style="color:#10b981; font-weight:bold; font-size:15px;">Accepted</span>
24 |         {% else %}
25 |           <span style="color:#f85149; font-weight:bold; font-size:15px;">Rejected</span>
26 |         {% endif %}
27 |       </div>
28 |     </div>
29 |     {# Ledger integrity badge -- calls anchor.check() at render time.
30 |        Three states: intact, tampered (hash fails), truncated (anchor mismatch). #}
31 |     <div>
32 |       <span style="font-size:11px; color:#8b949e; text-transform:uppercase;
33 |                    letter-spacing:0.07em;">Ledger integrity</span>
34 |       <div style="margin-top:4px;">
35 |         {% if integrity_status == "intact" %}
36 |           <span style="background:#1a4731; color:#10b981; border:1px solid #10b981;
37 |                        font-size:12px; padding:4px 14px; border-radius:3px; font-weight:bold;">
38 |             &#10003; intact
39 |           </span>
40 |         {% elif integrity_status == "tampered" %}
41 |           <span style="background:#3d1414; color:#f85149; border:1px solid #f85149;
42 |                        font-size:12px; padding:4px 14px; border-radius:3px; font-weight:bold;">
43 |             &#10007; tampered
44 |           </span>
45 |         {% else %}
46 |           <span style="background:#2d1a00; color:#f59e0b; border:1px solid #f59e0b;
47 |                        font-size:12px; padding:4px 14px; border-radius:3px; font-weight:bold;">
48 |             &#9888; truncated or replaced
49 |           </span>
50 |         {% endif %}
51 |       </div>
52 |     </div>
53 |   </div>
54 | 
55 |   <hr>
56 | 
57 |   {# Receipt detail #}
58 |   {% if receipt %}
59 |   <div style="margin:16px 0;">
60 |     <div style="font-size:11px; color:#8b949e; text-transform:uppercase;
61 |                 letter-spacing:0.07em; margin-bottom:10px;">Receipt</div>
62 |     <table style="max-width:680px; font-size:12px;">
63 |       <tbody>
64 |         <tr>
65 |           <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Author</td>
66 |           <td>{{ receipt.author }}</td>
67 |         </tr>
68 |         <tr>
69 |           <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Timestamp</td>
70 |           <td>{{ receipt.ts_display }}</td>
71 |         </tr>
72 |         <tr>
73 |           <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Card</td>
74 |           <td><span class="tag">{{ receipt.card_id }}</span></td>
75 |         </tr>
76 |         <tr>
77 |           <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">What changed</td>
78 |           <td>{{ receipt.what_changed }}</td>
79 |         </tr>
80 |         <tr>
81 |           <td style="color:#8b949e; padding:5px 12px 5px 0; white-space:nowrap;">Thesis state</td>
82 |           <td>
83 |             {% if receipt.thesis_state == "financing required before catalyst" %}
84 |               <span class="verdict-alert">{{ receipt.thesis_state }}</span>
85 |             {% elif receipt.thesis_state == "funded to catalyst" %}
86 |               <span class="verdict-ok">{{ receipt.thesis_state }}</span>
87 |             {% else %}
88 |               {{ receipt.thesis_state }}
89 |             {% endif %}
90 |           </td>
91 |         </tr>
92 |       </tbody>
93 |     </table>
94 |   </div>
95 | 
96 |   {# Hash chain: the most impressive thing in the system, made visible #}
97 |   <hr>
98 |   <div style="margin-top:16px;">
99 |     <div style="font-size:11px; color:#8b949e; text-transform:uppercase;
100 |                 letter-spacing:0.07em; margin-bottom:12px;">Hash chain</div>
101 | 
102 |     {# Chain diagram: observation -> Granite memo -> human decision -> hash verified #}
103 |     <div style="display:flex; align-items:center; gap:6px; flex-wrap:wrap;
104 |                 margin-bottom:16px; font-size:11px;">
105 |       <span style="background:#0d1117; border:1px solid #30363d; border-radius:3px;
106 |                    padding:4px 10px; color:#c9d1d9;">observation</span>
107 |       <span style="color:#30363d;">&#8594;</span>
108 |       <span style="background:#0d1117; border:1px solid #1e3a5f; border-radius:3px;
109 |                    padding:4px 10px; color:#60a5fa;">Granite memo</span>
110 |       <span style="color:#30363d;">&#8594;</span>
111 |       <span style="background:#0d1117; border:1px solid #30363d; border-radius:3px;
112 |                    padding:4px 10px; color:#c9d1d9;">human decision</span>
113 |       <span style="color:#30363d;">&#8594;</span>
114 |       {% if integrity_status == "intact" %}
115 |         <span style="background:#1a4731; border:1px solid #10b981; border-radius:3px;
116 |                      padding:4px 10px; color:#10b981; font-weight:bold;">hash verified</span>
117 |       {% elif integrity_status == "tampered" %}
118 |         <span style="background:#3d1414; border:1px solid #f85149; border-radius:3px;
119 |                      padding:4px 10px; color:#f85149; font-weight:bold;">hash FAILED</span>
120 |       {% else %}
121 |         <span style="background:#2d1a00; border:1px solid #f59e0b; border-radius:3px;
122 |                      padding:4px 10px; color:#f59e0b; font-weight:bold;">chain replaced</span>
123 |       {% endif %}
124 |     </div>
125 | 
126 |     <table style="max-width:680px; font-size:11px;">
127 |       <tbody>
128 |         <tr>
129 |           <td style="color:#8b949e; padding:4px 12px 4px 0; white-space:nowrap;">Prev hash</td>
130 |           <td style="font-family:ui-monospace,monospace; color:#6b7280;
131 |                      word-break:break-all;">{{ receipt.prev_hash }}</td>
132 |         </tr>
133 |         <tr>
134 |           <td style="color:#8b949e; padding:4px 12px 4px 0; white-space:nowrap;">Entry hash</td>
135 |           <td style="font-family:ui-monospace,monospace; color:#10b981;
136 |                      word-break:break-all;">{{ receipt.entry_hash }}</td>
137 |         </tr>
138 |       </tbody>
139 |     </table>
140 |   </div>
141 |   {% endif %}
142 | 
143 | </div>
144 | 
145 | <blockquote style="border-left:3px solid #30363d; padding-left:12px;
146 |                    color:#8b949e; font-size:11px; line-height:1.6;
147 |                    max-width:720px; margin-bottom:16px;">
148 |   Tamper demo: edit one byte of <code>data/decisions.jsonl</code> and reload to see
149 |   <strong>tampered</strong>. Delete the last entry and reload to see
150 |   <strong>truncated or replaced</strong>. The anchor detects these given that
151 |   <code>data/ledger.anchor</code> was not also rewritten.
152 | </blockquote>
153 | 
154 | <p style="font-size:12px;">
155 |   <a href="/redline">&larr; Back to redline</a>
156 |   &nbsp;|&nbsp;
157 |   <a href="/contracts">Contract list</a>
158 | </p>
159 | 
160 | {% endblock %}
161 |
